+    let rounds = 0;
+
+    // Phase 1: Prepare
+    rounds++;
+    const prepareVotes = this.participants.map((p) => {
+      const vote: Vote = {
+        agentId: p,
+        value: { phase: 'prepare', ready: Math.random() > 0.1 }, // 90% success rate
+        timestamp: Date.now(),
+      };
+      votes.push(vote);
+      return vote;
+    });
+
+    const allPrepared = prepareVotes.every(
+      (v) => (v.value as { ready: boolean }).ready
+    );
+
+    if (!allPrepared) {
+      // Abort
+      rounds++;
+      return {
+        achieved: false,
+        value: null,
+        votes,
+        rounds,
+        latency: performance.now() - startTime,
+      };
+    }
+
+    // Phase 2: Commit
+    rounds++;
+    const commitVotes = this.participants.map((p) => {
+      const vote: Vote = {
+        agentId: p,
+        value: { phase: 'commit', committed: true },
+        timestamp: Date.now(),
+      };
+      votes.push(vote);
+      return vote;
+    });
+
+    void commitVotes;
+
+    return {
+      achieved: true,
+      value: transaction,
+      votes,
+      rounds,
+      latency: performance.now() - startTime,
