+    if (achieved) {
+      candidate.state = 'leader';
+    } else {
+      candidate.state = 'follower';
+    }
+
+    return {
+      achieved,
+      value: achieved ? candidate.id : null,
+      votes,
+      rounds,
+      latency: performance.now() - startTime,
